PAT basic level 1019  数字黑洞  
PAT (Basic Level) Practice 乙级 1019给定任一个各位数字不完全相同的 4 位正整数，如果我们先把 4 个数字按非递增排序，再按非递减排序，然后用第 1 个数字减第 2 个数字，将得到一个新的数字。一直重复这样做，我们很快会停在有“数字黑洞”之称的 6174，这个神奇的数字也叫 Kaprekar 常数。例如，我们从6767开始，将得到7766 - 6677 = 10899810 - 0189 = 96219621 - 1269 = 83528532 - 2358 = 61747641 - 1467 = 6174… …现给定任意 4 位正整数，请编写程序演示到达黑洞的过程。输入格式：输入给出一个 (0,10​4​​) 区间内的正整数 N。输出格式：如果 N 的 4 位数字全相等，则在一行内输出 N - N = 0000；否则将计算的每一步在一行内输出，直到 6174 作为差出现，输出格式见样例。注意每个数字按 4 位数格式输出。输入样例 1：6767
输出样例 1：7766 - 6677 = 10899810 - 0189 = 96219621 - 1269 = 83528532 - 2358 = 6174
输入样例 2：2222
输出样例 2：2222 - 2222 = 0000

思路一：通过求出每一位数字后排序，并用数组保存数据（存在超时 14分）

#include &lt;iostream&gt;
#include&lt;algorithm&gt;
#include&lt;cstdio&gt;
using namespace std;
int main()
{
    int a,sum1,sum2,counts=0;
    cin&gt;&gt;a;
    int v[4];
    do{
        while(a&gt;1)
        {
            int temp=a%10;
            v[counts]=temp;
            a/=10;
            counts++;
        }
        sort(v,v+4);
        counts=0;
        sum1=v[0]*1000+v[1]*100+v[2]*10+v[3];
        sum2=v[3]*1000+v[2]*100+v[1]*10+v[0];
        a=sum2-sum1;
        if(sum1&lt;1000)
            printf(&quot;%d-0%d=%d\n&quot;,sum2,sum1,a);
        else
            printf(&quot;%d-%d=%d\n&quot;,sum2,sum1,a);
        if(a==0)
            break;
    }while(a!=6174);
    return 0;
}

思路二：通过字符串来处理数据，通过insert方法将不够四位的数补齐零

#include&lt;iostream&gt;
#include&lt;algorithm&gt;
#include&lt;string&gt;
using namespace std;
bool cmp(char a,char b)
{
    return a&gt;b;
}
int main()
{
    string s;
    cin&gt;&gt;s;
    s.insert(0,4-s.length(),&apos;0&apos;);
    do{
        string a=s,b=s;
        sort(a.begin(),a.end(),cmp);
        sort(b.begin(),b.end());
        int temp=stoi(a)-stoi(b);
        s=to_string(temp);
        s.insert(0,4-s.length(),&apos;0&apos;);
        cout&lt;&lt;a&lt;&lt;&quot; - &quot;&lt;&lt;b&lt;&lt;&quot; = &quot;&lt;&lt;s&lt;&lt;endl;
    }while(s!=&quot;6174&quot;&amp;&amp;s!=&quot;0000&quot;);
    return 0;
}

