}

在结构体中的使用带来了极大的便利
#include &lt;iostream&gt;
#include &lt;vector&gt;
#include &lt;algorithm&gt;

using namespace std;
struct student{
    int Calculus;
    int DataBase;
};

bool cmp(student a , student b){

    if(a.Calculus!=b.Calculus)
        //如果微积分成绩不相同 就按照微积分成绩由大到小排序
            return a.Calculus&gt;b.Calculus;
    else// 如果相同 就按照数据库成绩由大到小排序
           return a.DataBase&gt;b.DataBase;
}
int main(){
    //在C++中 结构体数组声明的写法不用多写额外的 struct
    vector&lt;student&gt; v;
    student temp;
    for(int i = 0 ;i &lt; 5; i++ ){
        cin&gt;&gt;temp.Calculus&gt;&gt;temp.DataBase;
        v.push_back(temp);
    }
    sort(v.begin(),v.end(),cmp);
}

PAT basic level 1021  个位数统计  
PAT (Basic Level) Practice 乙级 1021给定一个 k 位整数 N=d​k−1​​10​k−1​​+⋯+d​1​​10​1​​+d​0​​ (0≤d​i​​≤9, i=0,⋯,k−1, d​k−1​​&gt;0)，请编写程序统计每种不同的个位数字出现的次数。例如：给定 N=100311，则有 2 个 0，3 个 1，和 1 个 3。输入格式：每个输入包含 1 个测试用例，即一个不超过 1000 位的正整数 N。输出格式：对 N 中每一种不同的个位数字，以 D:M 的格式在一行中输出该位数字 D 及其在 N 中出现的次数 M。要求按 D 的升序输出。输入样例：100311
输出样例：0:21:33:1

思路：上来直接想到 Java的写法，通过map集合 键值对依次判断， 没有出现过的符号将值设置为1，出现过的值加1.

import java.util.HashMap;
import java.util.Map;
import java.util.Scanner;
import java.util.Set;
public class Main{
    public static void main(String[] args) {
        Map&lt;Character,Integer&gt; m1= new HashMap&lt;Character,Integer&gt;();
        Scanner input = new Scanner(System.in);
        String line=input.nextLine();
        char[] charArray = line.toCharArray();
        for(char s:charArray) {
             m1.put(s, m1.containsKey(s)? m1.get(s)+1:1);
        }
        for(Character s :m1.keySet()) {
            System.out.println(s+&quot;:&quot;+m1.get(s));
        }
    }
}

