本题本身没有太大的难度，按照所给的要求写出 简洁的代码才体现水平，自己写了好几个版本 几乎都在70行左右，于是参考大佬的代码学习一下，通过vector建立的的数组将余数不同类型的数字分类是关键，这样更加高效，同样性质的使用vector的还有1015题 。

#include &lt;iostream&gt;
#include &lt;vector&gt;
#include &lt;cstdio&gt;
using namespace std;
int main() {
    int n, temp, A1 = 0, A2 = 0, A5 = 0;
    double A4 =0.0;
    cin &gt;&gt; n;
    vector&lt;int&gt; v[5];
    for (int i = 0; i &lt; n; i++) {
        cin &gt;&gt; temp;
        v[temp%5].push_back(temp);
    }
    for (int i = 0; i &lt; 5; i++) {
        for (int j = 0; j &lt; v[i].size(); j++) {
            if (i==0&amp;&amp;v[i][j] % 2 == 0) A1 += v[i][j];
            if (i==1&amp;&amp;j%2 == 0) A2+=v[i][j];
            if (i==1&amp;&amp;j%2 == 1) A2-=v[i][j];
            if (i==3)A4+= v[i][j];
            if (i==4&amp;&amp;v[i][j] &gt; A5) A5=v[i][j];
        }
    }
    for (int i = 0; i &lt; 5; i++) {
        if (i != 0) printf(&quot; &quot;);
        if (i == 0 &amp;&amp; A1 == 0 || i != 0 &amp;&amp; v[i].size() == 0) {
            printf(&quot;N&quot;); continue;
        }
        if (i==0) printf(&quot;%d&quot;, A1);
        if (i==1) printf(&quot;%d&quot;, A2);
        if (i==2) printf(&quot;%d&quot;, v[2].size());
        if (i==3) printf(&quot;%.1f&quot;, A4 / v[3].size());
        if (i==4) printf(&quot;%d&quot;, A5);
    }
    return 0;
}

PAT basic level 1011  A+B 和 C  
